function m(){const e=document.documentElement,t=document.getElementById("theme-btn");e.classList.toggle("dark-mode"),e.classList.contains("dark-mode")?(localStorage.setItem("theme","dark"),t.textContent="☀️",t.setAttribute("title","الوضع النهاري")):(localStorage.setItem("theme","light"),t.textContent="🌙",t.setAttribute("title","الوضع الليلي"))}document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("theme-btn"),t=document.documentElement;localStorage.getItem("theme")==="dark"&&(t.classList.add("dark-mode"),e.textContent="☀️",e.setAttribute("title","الوضع النهاري")),e.addEventListener("click",m);const c=document.getElementById("menu-btn"),s=document.getElementById("mobile-menu");c.addEventListener("click",()=>{s.classList.toggle("active"),c.textContent=s.classList.contains("active")?"✕":"☰"});const o=document.getElementById("search-btn"),n=document.getElementById("search-panel"),a=document.getElementById("close-search");o.addEventListener("click",()=>{n.classList.add("active"),n.querySelector(".search-input").focus()}),a.addEventListener("click",()=>{n.classList.remove("active")}),document.addEventListener("keydown",d=>{d.key==="Escape"&&(n.classList.remove("active"),s.classList.remove("active"),c.textContent="☰")})});
